import{_ as t,a as r,b as a,c as o,d as i,e as s}from"./chunks/simplerov 5.Dabd9i25.js";import{_ as n,o as l,c as u,ag as d}from"./chunks/framework.DXGyWiRo.js";const q=JSON.parse('{"title":"Features","description":"","frontmatter":{},"headers":[],"relativePath":"robotics/features.md","filePath":"robotics/features.md"}'),h={name:"robotics/features.md"};function p(c,e,m,g,f,b){return l(),u("div",null,[...e[0]||(e[0]=[d('<h1 id="features" tabindex="-1">Features <a class="header-anchor" href="#features" aria-label="Permalink to &quot;Features&quot;">​</a></h1><p>ArduSub has many features including:</p><ul><li>Built-in support for several vehicle frame options and motor configurations (custom configurations are possible too)</li><li>High extensibility in software and hardware for customization</li><li>Attitude and Heading Reference System (AHRS) and Inertial Navigation Filter (EKF)</li><li>Extensive user-configurable parameter system</li><li>Well developed ground control station software for piloting and configuration</li><li>Compatibility with many development tools targeting MAVLink-enabled vehicles</li><li>Sensor and data logging</li><li><strong>No Programming Required</strong></li></ul><h2 id="supported-frames" tabindex="-1">Supported Frames <a href="#supported-frames" id="supported-frames"></a> <a class="header-anchor" href="#supported-frames" aria-label="Permalink to &quot;Supported Frames &lt;a href=&quot;#supported-frames&quot; id=&quot;supported-frames&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>ArduSub includes a high-level motor library that can configure motors in any configuration. This library is used to implement a number of supported frame configurations. All configurations are shown from <strong>top-down view</strong>. Green thrusters indicate counter-clockwise propellers and blue thrusters indicate clockwise propellers (or vice-versa). Currently supported are:</p><table tabindex="0"><thead><tr><th><p><img src="'+t+'" alt=""></p><p><strong>BlueROV1 Configuration</strong> with 6-DOF thruster positioning. (Frame: <code>bluerov</code>)</p></th><th><p><img src="'+r+'" alt=""></p><p><strong>Vectored ROV</strong> with side-by-side vertical thrusters. Used for the <a href="http://bluerov2.com/"><em>BlueROV2</em></a>. (Frame: <code>vectored</code>)</p></th><th><p><img src="'+a+'" alt=""></p><p><strong>Vectored ROV w/ Four Vertical Thrusters</strong>, an 8-thruster configuration with 6-DOF control and heavy-lifting capacity. Used for the <a href="https://bluerobotics.com/introducing-bluerov2-heavy/"><em>BlueROV2 Heavy</em></a>. (Frame: <code>vectored6dof</code>)</p></th></tr></thead><tbody><tr><td><p><img src="'+o+'" alt=""></p><p><strong>ROV</strong> with a single vertical thruster. (Frame: <code>simplerov</code>)</p></td><td><p><img src="'+i+'" alt=""></p><p><strong>ROV</strong> with side-by-side vertical thrusters. (Frame: <code>simplerov</code>)</p></td><td><p><img src="'+s+'" alt=""></p><p><strong>ROV</strong> with a lateral thruster and side-by-side vertical thrusters. (Frame: <code>simplerov</code>)</p></td></tr></tbody></table><h3 id="supported-hardware" tabindex="-1">Supported Hardware <a href="#supported-hardware" id="supported-hardware"></a> <a class="header-anchor" href="#supported-hardware" aria-label="Permalink to &quot;Supported Hardware &lt;a href=&quot;#supported-hardware&quot; id=&quot;supported-hardware&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>The ArduPilot project has support for a great variety of hardware platforms. ArduSub firmware is provided for many of these platforms, but <strong>only the Pixhawk 1 is fully tested and supported</strong>.</p><p>These are platforms that have been reported to work with ArduSub:</p><ul><li>Pixhawk</li><li>Pixhawk 2</li><li>Pixhawk Mini</li></ul><p>Please let us know if you have tested ArduSub on another platform!</p><h3 id="capabilities" tabindex="-1">Capabilities <a href="#capabilities" id="capabilities"></a> <a class="header-anchor" href="#capabilities" aria-label="Permalink to &quot;Capabilities &lt;a href=&quot;#capabilities&quot; id=&quot;capabilities&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><ul><li><strong>Feedback control and stability:</strong> Based on a multicopter autopilot system, the ArduSub controller has accurate feedback control to actively maintain orientation.</li><li><strong>Depth hold:</strong> Using pressure-based depth sensors, the ArduSub controller can maintain depth within a few centimeters.</li><li><strong>Heading hold:</strong> By default, the ArduSub automatically maintains its heading when not commanded to turn.</li><li><strong>Camera Tilt:</strong> Camera tilt control with servo or gimbal motors through the joystick or gamepad controller.</li><li><strong>Light Control:</strong> Control of subsea lighting through the joystick or gamepad controller.</li></ul><h3 id="extensibility" tabindex="-1">Extensibility <a href="#extensibility" id="extensibility"></a> <a class="header-anchor" href="#extensibility" aria-label="Permalink to &quot;Extensibility &lt;a href=&quot;#extensibility&quot; id=&quot;extensibility&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>In addition to the standard onboard sensors (IMU, compass), the ArduSub controller directly supports a number of external sensors including:</p><ul><li>Pressure/depth sensors for measurement and auto depth-hold (<a href="https://www.bluerobotics.com/store/electronics/bar30-sensor-r1/" target="_blank" rel="noreferrer">such as the Bar30</a>)</li></ul><p>Other sensors, and in particular high-bandwidth and specialized sensors, are integrated as <em>Companion</em> sensors, attached to the companion computer and running alongside <em>ArduSub</em> and sharing communication pathways. This allows rapid integration of new and unique payloads and allows you to use the manufacturer&#39;s user interface to control the sensor.</p><p>Sensors integration via companion includes sensors such as:</p><ul><li>Depth sounders (the <a href="https://bluerobotics.com/store/sensors-sonars-cameras/sonar/ping-sonar-r2-rp/" target="_blank" rel="noreferrer">Ping Sonar</a>)</li><li>UDP Input of external GPS data from underwater localization systems (<a href="https://www.bluerobotics.com/store/electronics/bar30-sensor-r1/" target="_blank" rel="noreferrer">such as the Water Linked Underwater GPS</a>)</li><li>Scanning Sonars (the <a href="https://bluerobotics.com/store/sensors-sonars-cameras/sonar/ping360-sonar-r1-rp/" target="_blank" rel="noreferrer">Ping360 Scanning Imaging Sonar</a>)</li></ul><p>With upcoming sensors:</p><ul><li>Conductivity sensors</li></ul><h3 id="results-matching" tabindex="-1">results matching &quot;&quot; <a class="header-anchor" href="#results-matching" aria-label="Permalink to &quot;results matching &quot;&quot;&quot;">​</a></h3><ul><li></li></ul><h3 id="no-results-matching" tabindex="-1">No results matching &quot;&quot; <a class="header-anchor" href="#no-results-matching" aria-label="Permalink to &quot;No results matching &quot;&quot;&quot;">​</a></h3>',24)])])}const _=n(h,[["render",p]]);export{q as __pageData,_ as default};
